10008 /// might be detected as a shuffle of 1 or 2 input vectors. If this attempt was
10009 /// successful, the matched scalars are replaced by poison values in \p VL for
10010 /// future analysis.
10011 SmallVector<std::optional<TTI::ShuffleKind>>
10012 BoUpSLP::tryToGatherExtractElements(SmallVectorImpl<Value *> &VL,
10013                                     SmallVectorImpl<int> &Mask,
10014                                     unsigned NumParts) const {
10015   assert(NumParts > 0 && "NumParts expected be greater than or equal to 1.");
10016   SmallVector<std::optional<TTI::ShuffleKind>> ShufflesRes(NumParts);
10017   Mask.assign(VL.size(), PoisonMaskElem);
10018   unsigned SliceSize = VL.size() / NumParts;
10019   for (unsigned Part = 0; Part < NumParts; ++Part) {
10020     // Scan list of gathered scalars for extractelements that can be represented
10021     // as shuffles.
10022     MutableArrayRef<Value *> SubVL =
10023         MutableArrayRef(VL).slice(Part * SliceSize, SliceSize);
10024     SmallVector<int> SubMask;
10025     std::optional<TTI::ShuffleKind> Res =
10026         tryToGatherSingleRegisterExtractElements(SubVL, SubMask);
10027     ShufflesRes[Part] = Res;
10028     copy(SubMask, std::next(Mask.begin(), Part * SliceSize));
10029   }
